# scripts/approval_notifier.py
import os, json, requests

SLACK_WEBHOOK = os.environ["SLACK_WEBHOOK_URL"]
PAGERDUTY_KEY = os.environ.get("PAGERDUTY_ROUTING_KEY")

def notify(record: dict) -> None:
    decision = record["decision"]
    color = {"approved": "#22c55e", "rejected": "#ef4444", "bypass": "#f59e0b"}[decision]
    digest_short = record["artifact_digest"].split(":")[-1][:12]

    msg = {
        "attachments": [{
            "color": color,
            "title": f"Promotion {decision.upper()}: {record['from_env']} -> {record['to_env']}",
            "fields": [
                {"title": "Actor", "value": record["actor"], "short": True},
                {"title": "Artifact", "value": digest_short, "short": True},
                {"title": "Accuracy", "value": str(record["eval_scores"].get("accuracy", "?")), "short": True},
                {"title": "Safety", "value": str(record["eval_scores"].get("safety", "?")), "short": True},
            ],
            "footer": record["event_id"],
            "ts": record["timestamp"],
        }]
    }
    requests.post(SLACK_WEBHOOK, json=msg).raise_for_status()

    # Page on bypass — always warrants attention
    if decision == "bypass" and PAGERDUTY_KEY:
        payload = {
            "routing_key": PAGERDUTY_KEY,
            "event_action": "trigger",
            "payload": {
                "summary": f"BYPASS: {record['from_env']}→{record['to_env']} by {record['actor']}",
                "severity": "warning",
                "source": "promotion-audit",
                "custom_details": record,
            },
        }
        requests.post("https://events.pagerduty.com/v2/enqueue", json=payload)
